VALUES
  ('elementary-f29af906-moex-00098', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例第20條之規定，需用土地人未於公告期滿15日內將應發給之補償費繳交該管直轄市或 縣（市）主管機關發給完竣者，該部分土地或土地改良物之徵收從此失其效力。但有特殊情形者不在此 限，下列何者非屬之？', '["經應受補償人以書面同意延期或分期發給", "應受補償人進行司法訴訟", "應受補償人拒絕受領或不能受領", "應受補償人所在地不明"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00099', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '私有土地經徵收計畫使用，在依法變更原使用目的後，由土地管理機關標售時，被徵收之原土地所有權人 未於決標後幾日內表示優先購買者，其優先購買權視為放棄？', '["5日", "10日", "15日", "20日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00100', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例之規定，有關得為區段徵收之情形，下列敘述何者錯誤？', '["新設都市地區之全部或一部，實施開發建設者", "海埔新生地，實施開發建設者", "舊都市地區為公共安全、衛生、交通之需要或促進土地之合理使用實施更新者", "都市土地之農業區、保護區變更為建築用地或工業區變更為住宅區、商業區者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00101', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依平均地權條例之規定，有關照價收買之原因，下列敘述何者錯誤？', '["申報地價未滿公告地價百分之八十者", "申報土地移轉現值，低於公告土地現值者", "閒置不用之農業用地，經加徵荒地稅滿5年仍不使用者", "超額未建築用地，經依法限期出售或使用，逾期未依法出售或使用者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00102', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依平均地權條例之規定，有關規定地價之程序，下列敘述何者錯誤？', '["分區調查最近1年之土地買賣價格或收益價格", "依據調查結果，劃分地價區段並估計區段地價後，提交地價評議委員會評議", "計算宗地單位地價", "公告及申報地價，其期限為60日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00103', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '關於地價稅之減免，依土地稅法等規定，下列敘述何者正確？', '["自用住宅用地之特別稅率為千分之四", "國民住宅、勞工宿舍用地之特別稅率為千分之四", "工業、礦業等用地之特別稅率為千分之十", "公有非公用土地之特別稅率為千分之五"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00104', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅法之規定，土地稅之納稅義務人之敘述，下列何者錯誤？', '["地價稅之納稅義務人為土地所有權人", "設有典權之土地，地價稅之納稅義務人為典權人", "土地為有償移轉者，土地增值稅之納稅義務人為取得所有權之人", "設有典權之土地，土地增值稅之納稅義務人為出典人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00105', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅法之規定，有關自用住宅用地土地增值稅之課徵，下列敘述何者錯誤？', '["土地所有權人出售其自用住宅用地者，都市土地面積未超過3公畝部分或非都市土地面積未超過7公 畝部分，其土地增值稅統就該部分之土地漲價總數額按百分之十徵收之", "土地於出售前1年內，曾供營業使用或出租者，不適用按百分之十徵收土地增值稅", "自用住宅之評定現值不及所占基地公告土地現值百分之十者，不適用按百分之十徵收土地增值稅", "土地所有權人，依自用住宅用地規定稅率繳納土地增值稅者，以一處為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00106', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依房屋稅條例之規定，房屋稅係依房屋現值課徵，有關住家用房屋課徵稅率之敘述，下列何者錯誤？', '["供自住、公益出租人出租使用或以土地設定地上權之使用權房屋並供該使用權人自住使用者，為其房屋 現值百分之一點二", "出租申報租賃所得達所得稅法第 14 條第 1 項第 5 類規定之當地一般租金標準者或繼承取得之共有房 屋，最低不得少於其房屋現值百分之一點五，最高不得超過百分之二點四", "起造人持有使用執照所載用途為住家用之待銷售房屋，於起課房屋稅 2 年內，最低不得少於其房屋現 值百分之二，最高不得超過百分之三點六", "其他住家用房屋，最低不得少於其房屋現值百分之一點五，最高不得超過百分之三"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00107', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅減免規則之規定，供公共通行之騎樓走廊地，無建築改良物者，應免徵地價稅，有建築改良物 者，依規定減徵地價稅，下列敘述何者正確？', '["地上有建築改良物一層者，減徵二分之一", "地上有建築改良物二層者，減徵四分之一", "地上有建築改良物三層者，減徵六分之一", "地上有建築改良物四層者，減徵八分之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
